mapper.select:
select o.id, o.number, o.status, o.pay_status as payStatus, o.user_id as userId, o.user_name as userName, o.consignee, o.phone, o.amount, o.pickup_code as pickupCode, o.order_time as orderTime, o.checkout_time as checkoutTime, o.pickup_deadline as pickupDeadline, coalesce(sum(od.number), 0) as itemCount from orders o left join order_detail od on od.order_id = o.id where 1 = 1
and ( cast(o.id as char) like concat('%', #{keyword}, '%') or o.number like concat('%', #{keyword}, '%') or o.phone like concat('%', #{keyword}, '%') or o.consignee like concat('%', #{keyword}, '%') or o.pickup_code like concat('%', #{keyword}, '%') )
and o.status = #{status}
and o.pay_status = #{payStatus}
group by o.id, o.number, o.status, o.pay_status, o.user_id, o.user_name, o.consignee, o.phone, o.amount, o.pickup_code, o.order_time, o.checkout_time, o.pickup_deadline order by ${sortColumn} ${sortOrder}, o.id desc limit #{pageSize} offset #{offset}

