mapper.update:
update orders
set status = #{targetStatus}
where id = #{id}
  and status = #{expectedStatus}

update inventory_batch
set
    locked_quantity = locked_quantity - #{quantity},
    sold_quantity = sold_quantity + #{quantity},
    update_time = #{updateTime}
where id = #{batchId}
  and locked_quantity >= #{quantity}
